DELIMITER $$
CREATE TRIGGER `sync_user_name_on_update` AFTER UPDATE ON `user_list` FOR EACH ROW BEGIN
    
    IF OLD.name != NEW.name THEN
        UPDATE U_log_login 
        SET name = NEW.name 
        WHERE userID = NEW.userId$$
DELIMITER ;

