--
-- Structure for view `vw_power_records_detail`
--
DROP TABLE IF EXISTS `vw_power_records_detail`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vw_power_records_detail`  AS SELECT `pr`.`id` AS `id`, `pr`.`deviceID` AS `deviceID`, `d`.`deviceName` AS `deviceName`, `d`.`ksaveID` AS `ksaveID`, `d`.`location` AS `location`, `pr`.`timestamp` AS `timestamp`, `pr`.`voltage` AS `voltage`, `pr`.`current` AS `current`, `pr`.`power` AS `power`, `pr`.`energy` AS `energy`, `pr`.`power_factor` AS `power_factor`, `pr`.`frequency` AS `frequency`, `pr`.`temperature` AS `temperature`, `pr`.`humidity` AS `humidity`, `pr`.`beforeMeterNo` AS `beforeMeterNo`, `pr`.`metricsMeterNo` AS `metricsMeterNo`, `d`.`status` AS `deviceStatus`, `pr`.`created_at` AS `created_at`, `pr`.`updated_at` AS `updated_at` FROM (`power_records` `pr` join `devices` `d` on(`pr`.`deviceID` = `d`.`deviceID`)) ORDER BY `pr`.`timestamp` DESC ;

